				d_unique_d_in2_sub2[ei_new] = d_unique_d_in2_sub_cumh[ori_col * d_common.in2_sub_cumh_rows + ori_row];
			}

#pragma omp barrier

#ifdef TEST_CHECKSUM
			if (bx == 0 && tx == 0) {
				for (int i = 0; i < d_common.in2_sub2_elem; i++) {
					checksum[11] = checksum[11] + d_unique_d_in2_sub2[i];
